<?php
namespace App\Http\Controllers;
use App\Models\Order;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Facades\DB;use Illuminate\View\View;
class CheckoutController extends Controller{public function index():View{$items=collect(session('cart',[]));if($items->isEmpty()){redirect()->route('cart.index')->send();}$total=$items->sum(fn($i)=>$i['price']*$i['quantity']);$discount=$total>10000000?$total*.05:0;return view('checkout.index',['items'=>$items,'total'=>$total,'discount'=>$discount,'final'=>$total-$discount]);}public function store(Request $r):RedirectResponse{$data=$r->validate(['customer_name'=>'required|string|max:255','customer_phone'=>'required|string|max:30','address'=>'required|string','province'=>'required|string|max:100','city'=>'required|string|max:100','postal_code'=>'nullable|string|max:20','notes'=>'nullable|string','payment_method'=>'required|string']);$items=collect(session('cart',[]));return DB::transaction(function()use($data,$items){$total=$items->sum(fn($i)=>$i['price']*$i['quantity']);$discount=$total>10000000?$total*.05:0;$order=Order::create($data+['order_number'=>'AI-'.now()->format('Ymd').'-'.random_int(1000,9999),'total_price'=>$total,'discount_amount'=>$discount,'final_price'=>$total-$discount,'status'=>'registered']);foreach($items as $item){$order->items()->create(['product_id'=>$item['id'],'product_name'=>$item['name'],'price'=>$item['price'],'quantity'=>$item['quantity'],'total'=>$item['price']*$item['quantity']]);}session()->forget('cart');return redirect()->route('orders.success',$order);});}}
